# ═══════════════════════════════════════════════════════════════
#  NOVA CLI — Windows Installer
#
#  Run this in PowerShell:
#  irm https://raw.githubusercontent.com/TU_USER/nova-os/main/install.ps1 | iex
#  irm http://TU_IP:3005/install.ps1 | iex
#
#  Self-contained. nova.py is embedded. Zero downloads needed.
# ═══════════════════════════════════════════════════════════════
$ErrorActionPreference = "Stop"
$NOVA_VERSION = "2.0.0"
$NOVA_DIR     = "$env:USERPROFILE\.nova"
$NOVA_PY      = "$NOVA_DIR\nova.py"
$NOVA_CMD     = "$NOVA_DIR\nova.cmd"

Clear-Host
Write-Host ""
Write-Host "  ███╗   ██╗ ██████╗ ██╗   ██╗ █████╗  " -ForegroundColor DarkBlue
Write-Host "  ████╗  ██║██╔═══██╗██║   ██║██╔══██╗ " -ForegroundColor DarkBlue
Write-Host "  ██╔██╗ ██║██║   ██║██║   ██║███████║ " -ForegroundColor Blue
Write-Host "  ██║╚██╗██║██║   ██║╚██╗ ██╔╝██╔══██║ " -ForegroundColor Blue
Write-Host "  ██║ ╚████║╚██████╔╝ ╚████╔╝ ██║  ██║ " -ForegroundColor Cyan
Write-Host "  ╚═╝  ╚═══╝ ╚═════╝   ╚═══╝  ╚═╝  ╚═╝ " -ForegroundColor Cyan
Write-Host ""
Write-Host "  Nova CLI  ·  Agents that answer for themselves." -ForegroundColor DarkGray
Write-Host "  ────────────────────────────────────────────"   -ForegroundColor DarkGray
Write-Host ""
Write-Host "  Installing Nova CLI v$NOVA_VERSION" -ForegroundColor White
Write-Host ""

function ok($msg)   { Write-Host "  " -NoNewline; Write-Host "✓" -ForegroundColor Green -NoNewline; Write-Host "  $msg" }
function err($msg)  { Write-Host "  " -NoNewline; Write-Host "✗" -ForegroundColor Red   -NoNewline; Write-Host "  $msg"; exit 1 }
function info($msg) { Write-Host "  " -NoNewline; Write-Host "·" -ForegroundColor Blue  -NoNewline; Write-Host "  $msg" -ForegroundColor DarkGray }

# Check Python
$PYTHON = $null
foreach ($cmd in @("python", "python3", "py")) {
    try {
        $ver = & $cmd -c "import sys; print(f'{sys.version_info.major}.{sys.version_info.minor}')" 2>$null
        $maj = [int](& $cmd -c "import sys; print(sys.version_info.major)" 2>$null)
        $min = [int](& $cmd -c "import sys; print(sys.version_info.minor)" 2>$null)
        if ($maj -ge 3 -and $min -ge 8) { $PYTHON = $cmd; ok "Python $ver"; break }
    } catch {}
}
if (-not $PYTHON) {
    err "Python 3.8+ no encontrado. Instala desde https://python.org — marca 'Add Python to PATH'"
}

# Create ~/.nova
if (-not (Test-Path $NOVA_DIR)) { New-Item -ItemType Directory -Path $NOVA_DIR -Force | Out-Null }
ok "Directorio: $NOVA_DIR"

# Write nova.py from embedded base64
Write-Host "  " -NoNewline; Write-Host "○" -ForegroundColor Blue -NoNewline; Write-Host "  Instalando nova.py..."
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes($NOVA_PY, $bytes)
ok "nova.py instalado"

# Create nova.cmd wrapper
$cmdContent = "@echo off`r`n$PYTHON `"$NOVA_PY`" %*`r`n"
[System.IO.File]::WriteAllText($NOVA_CMD, $cmdContent)
ok "Comando 'nova' creado"

# Add ~/.nova to user PATH
$userPath = [Environment]::GetEnvironmentVariable("PATH", "User")
if ($userPath -notlike "*\.nova*") {
    [Environment]::SetEnvironmentVariable("PATH", "$userPath;$NOVA_DIR", "User")
    $env:PATH += ";$NOVA_DIR"
    ok "PATH actualizado"
} else {
    ok "PATH ya incluye .nova"
}

# Test
try {
    & $PYTHON $NOVA_PY help | Out-Null
    ok "Nova CLI funciona"
} catch {
    err "Algo salió mal. Intenta manualmente: python $NOVA_PY help"
}

Write-Host ""
Write-Host "  ────────────────────────────────────────────" -ForegroundColor DarkGray
Write-Host ""
Write-Host "  Nova CLI instalado ✓" -ForegroundColor Green
Write-Host ""
Write-Host "  Próximos pasos:" -ForegroundColor White
Write-Host ""
Write-Host "  nova init         " -NoNewline -ForegroundColor Cyan; Write-Host " # conecta con tu servidor" -ForegroundColor DarkGray
Write-Host "  nova agent create " -NoNewline -ForegroundColor Cyan; Write-Host " # crea tu primer agente"  -ForegroundColor DarkGray
Write-Host "  nova status       " -NoNewline -ForegroundColor Cyan; Write-Host " # verifica el sistema"    -ForegroundColor DarkGray
Write-Host "  nova help         " -NoNewline -ForegroundColor Cyan; Write-Host " # todos los comandos"     -ForegroundColor DarkGray
Write-Host ""
Write-Host "  Abre una nueva terminal para que el PATH tome efecto." -ForegroundColor DarkGray
Write-Host ""
